// n8n Code node (JavaScript)

// 1) 读取 HTML 字符串（按你实际节点字段可调整）
// 常见来源：$json.body / $json.data / $json.html
const html =
  $json.body ??
  $json.data ??
  $json.html ??
  (typeof $json === 'string' ? $json : null);

if (!html || typeof html !== 'string') {
  throw new Error('未找到 HTML 字符串，请确认上游 GET 节点输出字段（如 body/data/html）。');
}

// 去掉标签并清理空白
function cleanText(str) {
  return str
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

// 按 class 提取 a 标签 href + 文本
function extractLinksByClass(className, limit = Infinity) {
  const escapedClass = className.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

  // class 必须包含目标类名；href 可在 class 前后
  const re = new RegExp(
    `<a\\b(?=[^>]*\\bclass=["'][^"']*\\b${escapedClass}\\b[^"']*["'])[^>]*\\bhref=["']([^"']+)["'][^>]*>([\\s\\S]*?)<\\/a>`,
    'gi'
  );

  const out = [];
  let m;
  while ((m = re.exec(html)) !== null) {
    out.push({
      href: m[1].trim(),
      text: cleanText(m[2]),
    });
    if (out.length >= limit) break;
  }
  return out;
}

const result = {
  blockLink_b1pjlb0j: extractLinksByClass('blockLink_b1pjlb0j'),
  blockLink_b1rzlw4n: extractLinksByClass('blockLink_b1rzlw4n'),
  blockLink_bzngw6j: extractLinksByClass('blockLink_bzngw6j', 8), // 只要前8个
};

return [{ json: result }];

// 输入是你当前提取结果：
// $json.blockLink_b1pjlb0j, $json.blockLink_b1rzlw4n, $json.blockLink_bzngw6j
const groups = [
  $json.blockLink_b1pjlb0j || [],
  $json.blockLink_b1rzlw4n || [],
  $json.blockLink_bzngw6j || [],
];

const articles = groups
  .flat()
  .filter(x => x && x.href && x.text)
  .map((x, i) => ({
    id: i + 1,
    title: String(x.text).trim(),
    url: x.href.startsWith('http') ? x.href : `https://www.nikkei.com${x.href}`,
  }));

const article_titles = groups
  .flat()
  .filter(x => x && x.href && x.text)
  .map((x, i) => ({
    id: i + 1,
    title: String(x.text).trim()
  }));

return [{ json: { article_titles,articles } }];

const ts = $('整合URL1').first().json.article_titles || [];
const removeId = Number($('筛选').first().json.matched_article.id);

// 先过滤，再映射
return [{ json: { article_titles:ts
  .filter((item) => Number(item.id) != removeId)
  .map((item) => (item)) } }] ;

// n8n Code 节点（Run Once for All Items）
// 前提：AI文本一定可拿到，并且其中包含 "top_hot_news_id"

const rawText = $input.first().json.choices[
    0
].message.content || "";

// 直接从文本里提取 top_hot_news_id
const topIdMatch = rawText.match(/"top_hot_news_id"\s*:\s*(\d+)/);
const top_id = topIdMatch ? Number(topIdMatch[
    1
]) : null;

// 在 articles 中找对应 id
const articles = Array.isArray($('整合URL1').first().json.articles) ? $('整合URL1').first().json.articles : [];
const matched_article =
  top_id === null ? null : articles.find((a) => Number(a.id) === top_id) || null;

return {
  json: {
    top_id,
    matched_article,
    matched_found: !!matched_article,
    },
};

const html = $('获取新闻详情内容').first().json.data || "";

let news_content = "";
let news_content_html = "";
let image_urls = [];

// 只匹配：<section class="... container_campx13 ...">...</section>
const sectionMatch = html.match(
  /<section\b[^>]*class="[^"]*\bcontainer_campx13\b[^"]*"[^>]*>([\s\S]*?)<\/section>/i
);

if (sectionMatch) {
  let inner = sectionMatch[1];

  // 删除 section 内 class 含 container_cck592u 的元素（成对标签 + 自闭合）
  inner = inner
    .replace(/<([a-z0-9]+)\b[^>]*class="[^"]*\bcontainer_cck592u\b[^"]*"[^>]*>[\s\S]*?<\/\1>/gi, "")
    .replace(/<([a-z0-9]+)\b[^>]*class="[^"]*\bcontainer_cck592u\b[^"]*"[^>]*\/>/gi, "");

  // 把每个 figure 压缩成 figure 内第一张 img（没有 img 就删除 figure）
  inner = inner.replace(/<figure\b[^>]*>[\s\S]*?<\/figure>/gi, (figureHtml) => {
    const imgMatch = figureHtml.match(/<img\b[^>]*>/i);
    return imgMatch ? imgMatch[0] : "";
  });

  news_content_html = inner.trim();

  // 提取图片链接（src / data-src）
  const imgRegex = /<img\b[^>]*(?:src|data-src)=["']([^"']+)["'][^>]*>/gi;
  let m;
  while ((m = imgRegex.exec(news_content_html)) !== null) {
    image_urls.push(m[1]);
  }
  image_urls = [...new Set(image_urls)];

  // 转纯文本（保留分段换行）
  news_content = news_content_html
    .replace(/<\s*br\s*\/?>/gi, "\n")
    .replace(/<\/\s*(p|div|li|h2|h3|blockquote)\s*>/gi, "\n")
    .replace(/<script[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?<\/style>/gi, "")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/gi, " ")
    .replace(/&amp;/gi, "&")
    .replace(/&lt;/gi, "<")
    .replace(/&gt;/gi, ">")
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]+\n/g, "\n")
    .trim();
}

return [
  {
    json: {
      news_content,       // 纯文本（保留换行）
      news_content_html,  // HTML（figure 已压缩成 img）
      image_urls,         // 图片链接数组
    },
  },
];

